import React from 'react';
import './Design.css';
import IMG from './IMG.jpg';


function Navbar() {
  return (
    <div>
      <ul className='header'>
        <li>Home</li>
        <li>About</li>
        <li>Project</li>
        <li>Contact</li>
      </ul>
      <div>
      <img src={IMG} className='image' alt='/' />
     <p className='text'>Hi I am Anand Agarwal <br/> Web developer</p>
      </div>
    </div>
  );
}

export default Navbar;
